label("$C$",(f(15*sqrt(3)/4),15*sqrt(3)/4),ENE);
label("$D$",(-f(5*sqrt(3)/2),5*sqrt(3)/2),WNW);
label("$E$",(f(5*sqrt(3)/2),5*sqrt(3)/2),ENE);
label("$F$",(-f(5*sqrt(3)/4),5*sqrt(3)/4),WNW);
label("$G$",(f(5*sqrt(3)/4),5*sqrt(3)/4),ENE);
label("$H$",(-5,0),W);
label("$I$",(5,0),E);[/asy]

